# Discord Ban Bot (Discord.js v14)

Here's a complete implementation of a Discord bot with a `ban` slash command.

## Project Structure

```
discord-ban-bot/
├── node_modules/
├── commands/
│   └── ban.js
├── config.json
├── deploy-commands.js
├── index.js
└── package.json
```

## 1. Install Dependencies

```bash
npm init -y
npm install discord.js
```

## 2. `config.json`

Store your bot credentials here.

```json
{
    "token": "YOUR_BOT_TOKEN",
    "clientId": "YOUR_CLIENT_ID",
    "guildId": "YOUR_GUILD_ID"
}
```

> **Note:** `guildId` is used for instant command registration during development. For global commands, see the deploy script comments.

## 3. `commands/ban.js`

This file defines the ban command.

```javascript
const { SlashCommandBuilder, PermissionFlagsBits } = require('discord.js');

module.exports = {
    data: new SlashCommandBuilder()
        .setName('ban')
        .setDescription('Bans a member from the server.')
        .addUserOption(option =>
            option
                .setName('target')
                .setDescription('The member to ban')
                .setRequired(true))
        .addStringOption(option =>
            option
                .setName('reason')
                .setDescription('The reason for the ban')
                .setRequired(false))
        .addIntegerOption(option =>
            option
                .setName('delete_days')
                .setDescription('Days of messages to delete (0-7)')
                .setMinValue(0)
                .setMaxValue(7)
                .setRequired(false))
        // Only users with Ban Members permission can see/use this command
        .setDefaultMemberPermissions(PermissionFlagsBits.BanMembers)
        // Bans only make sense in a guild
        .setDMPermission(false),

    async execute(interaction) {
        const target = interaction.options.getUser('target');
        const reason = interaction.options.getString('reason') ?? 'No reason provided';
        const deleteDays = interaction.options.getInteger('delete_days') ?? 0;

        // Fetch the member object (may be null if user isn't in the guild)
        const member = await interaction.guild.members
            .fetch(target.id)
            .catch(() => null);

        // --- Validation checks ---

        // Prevent banning yourself
        if (target.id === interaction.user.id) {
            return interaction.reply({
                content: '❌ You cannot ban yourself.',
                ephemeral: true,
            });
        }

        // Prevent banning the bot
        if (target.id === interaction.client.user.id) {
            return interaction.reply({
                content: '❌ I cannot ban myself.',
                ephemeral: true,
            });
        }

        if (member) {
            // Check if the target is bannable by the bot
            if (!member.bannable) {
                return interaction.reply({
                    content: '❌ I cannot ban this user. They may have a higher role than me, or I lack permissions.',
                    ephemeral: true,
                });
            }

            // Check role hierarchy between command issuer and target
            if (
                interaction.member.roles.highest.position <=
                member.roles.highest.position &&
                interaction.guild.ownerId !== interaction.user.id
            ) {
                return interaction.reply({
                    content: '❌ You cannot ban someone with an equal or higher role than you.',
                    ephemeral: true,
                });
            }
        }

        // --- Attempt the ban ---
        try {
            await interaction.guild.members.ban(target.id, {
                deleteMessageSeconds: deleteDays * 24 * 60 * 60,
                reason: `${reason} | Banned by ${interaction.user.tag}`,
            });

            await interaction.reply({
                content: `✅ **${target.tag}** has been banned.\n**Reason:** ${reason}`,
            });
        } catch (error) {
            console.error('Error banning user:', error);
            await interaction.reply({
                content: '❌ An error occurred while trying to ban this user.',
                ephemeral: true,
            });
        }
    },
};
```

## 4. `deploy-commands.js`

Run this script to register your slash commands with Discord.

```javascript
const { REST, Routes } = require('discord.js');
const { token, clientId, guildId } = require('./config.json');
const fs = require('node:fs');
const path = require('node:path');

const commands = [];
const commandsPath = path.join(__dirname, 'commands');
const commandFiles = fs
    .readdirSync(commandsPath)
    .filter(file => file.endsWith('.js'));

// Load command data from each command file
for (const file of commandFiles) {
    const filePath = path.join(commandsPath, file);
    const command = require(filePath);
    if ('data' in command && 'execute' in command) {
        commands.push(command.data.toJSON());
    } else {
        console.log(`[WARNING] The command at ${filePath} is missing "data" or "execute".`);
    }
}

const rest = new REST().setToken(token);

(async () => {
    try {
        console.log(`Started refreshing ${commands.length} application (/) command(s).`);

        // Guild-based commands deploy instantly (great for development).
        const data = await rest.put(
            Routes.applicationGuildCommands(clientId, guildId),
            { body: commands },
        );

        // For GLOBAL commands (can take up to 1 hour to update), use:
        // const data = await rest.put(
        //     Routes.applicationCommands(clientId),
        //     { body: commands },
        // );

        console.log(`Successfully reloaded ${data.length} application (/) command(s).`);
    } catch (error) {
        console.error(error);
    }
})();
```

## 5. `index.js`

The main bot file.

```javascript
const fs = require('node:fs');
const path = require('node:path');
const { Client, Collection, Events, GatewayIntentBits } = require('discord.js');
const { token } = require('./config.json');

// Create the client. Guilds intent is required for slash commands.
const client = new Client({ intents: [GatewayIntentBits.Guilds] });

// Attach a collection to store commands
client.commands = new Collection();

// --- Load command files ---
const commandsPath = path.join(__dirname, 'commands');
const commandFiles = fs
    .readdirSync(commandsPath)
    .filter(file => file.endsWith('.js'));

for (const file of commandFiles) {
    const filePath = path.join(commandsPath, file);
    const command = require(filePath);
    if ('data' in command && 'execute' in command) {
        client.commands.set(command.data.name, command);
    } else {
        console.log(`[WARNING] The command at ${filePath} is missing "data" or "execute".`);
    }
}

// --- Bot ready event ---
client.once(Events.ClientReady, readyClient => {
    console.log(`✅ Ready! Logged in as ${readyClient.user.tag}`);
});

// --- Handle interactions ---
client.on(Events.InteractionCreate, async interaction => {
    // Only handle chat input (slash) commands
    if (!interaction.isChatInputCommand()) return;

    const command = client.commands.get(interaction.commandName);

    if (!command) {
        console.error(`No command matching ${interaction.commandName} was found.`);
        return;
    }

    try {
        await command.execute(interaction);
    } catch (error) {
        console.error(error);
        const errorMessage = {
            content: '❌ There was an error while executing this command!',
            ephemeral: true,
        };

        if (interaction.replied || interaction.deferred) {
            await interaction.followUp(errorMessage);
        } else {
            await interaction.reply(errorMessage);
        }
    }
});

// Log in to Discord
client.login(token);
```

## How to Run

1. **Fill in `config.json`** with your bot token, client ID, and guild ID.
2. **Deploy the commands** (run once, or whenever you change command definitions):
   ```bash
   node deploy-commands.js
   ```
3. **Start the bot:**
   ```bash
   node index.js
   ```

## Required Bot Setup

In the [Discord Developer Portal](https://discord.com/developers/applications):

1. Create an application and a bot.
2. Under **Bot**, copy the token into `config.json`.
3. Invite the bot with the `bot` and `applications.commands` scopes, plus the **Ban Members** permission. Example invite URL (replace `CLIENT_ID`):
   ```
   https://discord.com/api/oauth2/authorize?client_id=CLIENT_ID&permissions=4&scope=bot%20applications.commands
   ```
4. Ensure the bot's role is **above** the roles of members you want to ban in the server's role hierarchy.

## Key Features

| Feature | Description |
|---------|-------------|
| **Permission gating** | `setDefaultMemberPermissions` hides the command from users without Ban Members |
| **Self/bot protection** | Prevents banning yourself or the bot |
| **Role hierarchy checks** | Validates both bot and issuer can act on the target |
| **Message deletion** | Optional `delete_days` option to purge recent messages |
| **Reason logging** | Reason appears in the audit log with the moderator's tag |
| **Off-server bans** | Works even if the user already left (uses user ID) |

Let me know if you'd like to add features such as DMing the banned user, logging to a mod channel, or an unban command!
